import React, { Component, useCallback, useEffect, useState } from 'react';
import PropTypes from 'prop-types';
import {connect, useDispatch, useSelector} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { 
    headerActions, headerStrings, breadCrumbActions, MyTable, EditableCellMapFormat,
    hirUtilStrings, appActions, alertAction, getEditableCellMapFormatNewValues
 } from "../../utils";
import { hirRouteNames } from '../../routeNames';
import { Accordion, AccordionSummary, AccordionDetails, Button, makeStyles } from '@material-ui/core';
import { hirSettingActions } from '../actions'; 
import { history } from '../../../../helpers';
import { hirSettingStrings } from '../config';
let settings = [
    {
        _id : 1,
        name : "revenueCategories",
        header : "Revenue Category",
        values : [
            {name : "record", value : "New Folder"},
            {name : "appointment", value : "Appointments"}
        ]
    },
    {
        _id : 1,
        name : "units",
        header : "Hospital Units",
        values : [
            {name : "record", value : "Records"},
            {name : "physiotherapy", value : "Physiotherapy"}
        ]
    },
]
const style = makeStyles(theme => ({
    root: {
    },
    summary : {
        backgroundColor : theme.colors.primary1,
        color : theme.colors.white,
    },
    details : {
        padding : 5,
    },
    accordion : {
        marginBottom : 10,
    }
}))
function HIRSettingAdmin(props){
    const classes = style(),
    dispatch = useDispatch(),
    [state, _setState] = useState({
        settings : null, 
        newSettingValueContext : {}
    }),
    setState = (_state, calllback) => _setState(state=>({...state, ..._state}), calllback),
    {
        settings, newSettingValueContext
    } = state,
    {hirUtilReducer, hirSettingReducer} = useSelector(state=>state),
    {
        [hirUtilStrings.myProfile] : profile
    } = hirUtilReducer,
    {
        [hirSettingStrings.settings] : receivedSettings
    } = hirSettingReducer;
    useEffect(() => {
        headerActions({
            [headerStrings.headerTitle] : "CLINICAL SETTINGS",
        })(dispatch);
        breadCrumbActions.setBreadCrumb([
            {name : "Dashboard", path : hirRouteNames.dashboard},
            {name : "Clinical Settings", path : hirRouteNames.settings}
        ])(dispatch);
        if(!profile || [0, 11].indexOf(profile.privilege) === -1)
            history.replace(hirRouteNames.dashboard);
    }, []);
    useEffect(() => {
        setState({settings : receivedSettings});
    }, [JSON.stringify(receivedSettings)]);
    const cellMapFormat = useCallback(superProps => props => <EditableCellMapFormat {...props} {...superProps}/>, []),
    getSettings = () => hirSettingActions.getSettings()(dispatch),
    addButtonHandler = useCallback(({_id, name, header}) => length => () => {
        const {value} = getEditableCellMapFormatNewValues(newSettingValueContext[_id]) || {};
        const {dispatch} = props;
        if(!value || !String(value).trim()){
            appActions.showSnackbar(
                alertAction.error("value for "+header+" can not be empty")
            )(dispatch);
            return;
        }
        hirSettingActions.addSettingValue({
            settingId : _id, 
            settingName : name, 
            value
        }, (done)=>{
            if(done) getSettings();
        })(dispatch);
    },[/* JSON.stringify(newSettingValueContext) */]),
    editBtnHandler = useCallback(({_id}) => row => () => {
        if(settings){
            const newSettings = [
                ...settings.map(
                    item=>{
                        return item._id === _id ? 
                        {...item, values : 
                            [...item.values.map(v=>{
                                return v.name === row.name ? 
                                    {...v, editing : true} :
                                v;
                            })]
                        }
                        : item
                    }                    
                )
            ]
            setState({settings : newSettings})
        }
    }, [JSON.stringify(settings)]),
    deleteBtnHandler = useCallback(({_id, header}) => row => () => {
        appActions.showSnackDialog("Are you want to delete "+row.value+" from "+header+"?", [
            <Button key={"delete"+_id} onClick={() => {
                appActions.closeSnackDialog()(dispatch);
                hirSettingActions.deleteSettingValue(_id, row.name, done =>{
                    done && hirSettingActions.getSettings()(dispatch);
                })(dispatch);
            }}>Delete</Button>
        ])(dispatch);
    }, []),
    editFinishBtnHandler = ({_id, header}) => (row) => () => {
        const {dispatch} = props;
        const {value} = getEditableCellMapFormatNewValues(row.context);
        if(!String(value).trim()){
            appActions.showSnackbar(
                alertAction.error("Value of "+header+" can not be empty")
            )(dispatch);
            return;
        }
        appActions.showSnackDialog(
            "Are you sure you want to modify this item?",
            [<Button key={"edit"+_id} onClick={() =>{
                appActions.closeSnackDialog()(dispatch);
                const valueName = row.name;
                hirSettingActions.editSettingValue(_id, valueName, value, done => {
                    if(done) {
                        cancelEditBtnHandler({_id})({name : valueName});
                        getSettings();
                    }
                })(dispatch);
            }}>
                Modify
            </Button>]
        )(dispatch);
    },
    cancelEditBtnHandler = useCallback(({_id}) => row => () => {
        if(settings){
            const newSettings = [
                ...settings.map(
                    item=>{
                        return item._id === _id ? 
                        {...item, values : 
                            [...item.values.map(v=>{
                                if(v.name === row.name)
                                    delete v.editing;
                                return v;
                            })]
                        }
                        : item
                    }                    
                )
            ]
            setState({settings : newSettings})
        }
    }, [JSON.stringify(settings)]);
    return (
        <div className={classes.root}>
            {settings && settings.map((item, index)=>{
                if(["revenue"].indexOf(item.name) === -1) return null;
                const data = item.values ? 
                    [...item.values.map(item=>({...item, editable : true, delible : true})), {new : true}] : 
                    [{new : true}];
                return <Accordion classes={{
                    root : classes.accordion
                }} key={index}>
                    <AccordionSummary className={classes.summary}>
                        {item.header}
                    </AccordionSummary>
                    <AccordionDetails className={classes.details}>
                        <MyTable
                            elevation={0}
                            header={["Values", "Actions"]}
                            dataMap={["value", "action"]}
                            CellMap={cellMapFormat({
                                getContext : (context, cellMap) => {
                                    if(!newSettingValueContext[item._id]){
                                        newSettingValueContext[item._id] = {};
                                        newSettingValueContext[item._id][cellMap] = context;
                                    }else newSettingValueContext[item._id][cellMap] = context;
                                    // setState({newSettingValueContext})
                                    state.newSettingValueContext = newSettingValueContext;
                                },
                                addButtonHandler : addButtonHandler(item),
                                editBtnHandler : editBtnHandler(item),
                                deleteBtnHandler : deleteBtnHandler(item),
                                editFinishBtnHandler : editFinishBtnHandler(item),
                                cancelEditBtnHandler : cancelEditBtnHandler(item),
                            })}
                            data={data}
                            />
                    </AccordionDetails>
                </Accordion>
            })}
        </div>
    );
}


HIRSettingAdmin.propTypes = {
    classes : PropTypes.object.isRequired
};
export default HIRSettingAdmin;
export {HIRSettingAdmin}